/**
 * Misconception graph — typed loader for generated JSON data.
 *
 * @remarks
 * Generated by the misconception graph JSON writer.
 * Imports raw JSON data and re-exports it with TypeScript interfaces.
 */
import { createRequire } from 'node:module';
import type { MisconceptionGraph } from './types.js';

const require = createRequire(import.meta.url);
// Direct type annotation is acceptable here: MisconceptionGraph contains only
// primitive fields (string, Record<string, number>) with no union literals
// requiring runtime validation. See prerequisite-graph/index.ts for the
// two-step validation pattern used when union narrowing is needed.
const data: MisconceptionGraph = require('./data.json');

/**
 * Misconception graph with common mistakes and teacher responses.
 *
 * @remarks
 * Contains misconceptions extracted from curriculum lessons.
 * Use for identifying common mistakes and providing targeted support.
 */
export const misconceptionGraph: MisconceptionGraph = data;

export type { MisconceptionGraph, MisconceptionGraphStats, MisconceptionNode } from './types.js';
